using Typewriter.Abstractions;
using Typewriter.Engine;
using Xunit;

namespace Typewriter.Engine.Tests;

public sealed class ExternalRecipeCompatibilityTests
{
    [Fact]
    public void RenderSupportsAngularSystemTextJsonServiceRecipe()
    {
        var recipePath = ResolveExternalRecipePath(
            "Angular",
            "System.Text.Json",
            "services",
            "_AutogeneratedServices.tst");
        if (!File.Exists(path: recipePath))
        {
            return;
        }

#pragma warning disable SEC0116
        var templateContent = File.ReadAllText(path: recipePath);
#pragma warning restore SEC0116
        var metadata = CreateAngularWebApiMetadata();
        var diagnostics = new List<GenerationDiagnostic>();
        var renderer = new TemplateRenderer(typeMapper: new TypeScriptTypeMapper());
        var document = TemplateDocument.Parse(template: new TemplateFile(Path: recipePath, Content: templateContent), diagnostics: diagnostics);

        var output = renderer.Render(template: document, metadata: metadata, diagnostics: diagnostics);

        diagnostics.Should().NotContain(diagnostic => diagnostic.Severity != DiagnosticSeverity.Info);
        output.Should().Contain("import { UserDto } from '../models/UserDto';");
        output.Should().Contain("import { CreateUserRequest } from '../models/CreateUserRequest';");
        output.Should().Contain("export interface IApiUsersService");
        output.Should().Contain("export class ApiUsersService implements IApiUsersService");
        output.Should().Contain("getItemAsyncnumberstring(id: number, search: string)");
        output.Should().NotContain("getItemAsyncnumberstring | null");
        output.Should().Contain("this.usersServiceUrl");
        output.Should().Contain("items/{id}");
        output.Should().Contain("items");
        output.Should().Contain("request,");
    }

    [Fact]
    public void RenderSupportsAngularSystemTextJsonModelRecipeDefaults()
    {
        var recipePath = ResolveExternalRecipePath(
            "src",
            "AngularWebApiSample",
            "ClientApp",
            "apps",
            "client-app",
            "src",
            "api",
            "models",
            "_AutogeneratedModels.tst");
        if (!File.Exists(path: recipePath))
        {
            return;
        }

#pragma warning disable SEC0116
        var templateContent = File.ReadAllText(path: recipePath);
#pragma warning restore SEC0116
        var metadata = CreateAngularWebApiModelMetadata();
        var diagnostics = new List<GenerationDiagnostic>();
        var renderer = new TemplateRenderer(typeMapper: new TypeScriptTypeMapper());
        var document = TemplateDocument.Parse(template: new TemplateFile(Path: recipePath, Content: templateContent), diagnostics: diagnostics);

        var output = renderer.Render(template: document, metadata: metadata, diagnostics: diagnostics);

        diagnostics.Should().NotContain(diagnostic => diagnostic.Severity != DiagnosticSeverity.Info);
        output.Should().Contain("import { SimpleModel } from './SimpleModel';");
        output.Should().Contain("middleName?: string | null;");
        output.Should().Contain("this.id = initObj.id ?? 0;");
        output.Should().Contain("this.simpleModels = initObj.simpleModels ?? [];");
        output.Should().Contain("this.firstName = initObj.firstName ?? '';");
        output.Should().Contain("this.middleName = initObj.middleName ?? null;");
        output.Should().Contain("this.lastName = initObj.lastName ?? '';");
        output.Should().Contain("this.firstSet = initObj.firstSet ?? FirstSet.ValA;");
        output.Should().Contain("this.secondSet = initObj.secondSet ?? SecondSet.ValA;");
    }

    [Fact]
    public void RenderSupportsAngularSystemTextJsonRuntimeSchemaRecipe()
    {
        var recipePath = ResolveExternalRecipePath(
            "Angular",
            "System.Text.Json",
            "models",
            "_AutogeneratedRuntimeSchemas.tst");
        if (!File.Exists(path: recipePath))
        {
            return;
        }

#pragma warning disable SEC0116
        var templateContent = File.ReadAllText(path: recipePath);
#pragma warning restore SEC0116
        var metadata = CreateAngularWebApiModelMetadata();
        var diagnostics = new List<GenerationDiagnostic>();
        var renderer = new TemplateRenderer(typeMapper: new TypeScriptTypeMapper());
        var document = TemplateDocument.Parse(
            template: new TemplateFile(Path: recipePath, Content: templateContent),
            diagnostics: diagnostics);

        var output = renderer.Render(template: document, metadata: metadata, diagnostics: diagnostics);

        diagnostics.Should().NotContain(diagnostic => diagnostic.Severity != DiagnosticSeverity.Info);
        output.Should().Contain("'firstSet': schema.property(schema.optional((schema.number() as RuntimeSchema<FirstSet>)))");
        output.Should().Contain("'secondSet': schema.property(schema.optional((schema.string() as RuntimeSchema<SecondSet>)))");
        output.Should().Contain("schema.array(schema.reference<SimpleModel>('AngularWebApiSample.Models.SimpleModel'))");
        output.Should().NotContain("$Properties");
    }

    private static string ResolveExternalRecipePath(params string[] relativeParts)
    {
        var repositoryRoot = FindRepositoryRoot();
        var gitHubRoot = Directory.GetParent(path: repositoryRoot)?.FullName ?? repositoryRoot;
        return Path.Combine(paths: [gitHubRoot, "NetCoreTypewriterRecipes", .. relativeParts]);
    }

    private static string FindRepositoryRoot()
    {
        var directory = new DirectoryInfo(path: AppContext.BaseDirectory);
        while (directory is not null)
        {
            if (File.Exists(path: Path.Combine(path1: directory.FullName, path2: "AdaskoTheBeAsT.Typewriter.slnx")))
            {
                return directory.FullName;
            }

            directory = directory.Parent;
        }

        return AppContext.BaseDirectory;
    }

