            isEnum: true);
        var secondSetType = TypeReference(
            name: "SecondSet",
            fullName: SecondSetFullName,
            isNullable: false,
            isPrimitive: false,
            isEnum: true);
        var simpleModelsType = TypeReference(
            name: "List",
            fullName: "System.Collections.Generic.List",
            isNullable: false,
            isPrimitive: false,
            isCollection: true,
            elementType: simpleModelType,
            typeArguments: [simpleModelType]);

        var combinedQueryModel = new TypeMetadata(
            Name: "CombinedQueryModel",
            FullName: CombinedFullName,
            Namespace: "AngularWebApiSample.Models",
            Kind: TypeMetadataKind.Class,
            Accessibility: MetadataAccessibility.Public,
