    private static EnumValueMetadata CreateEnumValue(
        string parentFullName,
        string name,
        long value)
    {
        return new EnumValueMetadata(Name: name, Value: value)
        {
            ParentTypeFullName = parentFullName,
        };
    }

    private static PropertyMetadata CreateProperty(
        string parentFullName,
        string name,
        TypeMetadataReference type)
    {
        return new PropertyMetadata(
            Name: name,
            FullName: parentFullName + "." + name,
            Type: type,
            Accessibility: MetadataAccessibility.Public,
            HasGetter: true,
            HasSetter: true,
            IsRequired: false,
            Attributes: [])
        {
            ParentTypeFullName = parentFullName,
        };
    }

    private static TypeMetadataReference TypeReference(
        string name,
        string fullName,
        bool isNullable,
        bool? isPrimitive = null,
        bool isCollection = false,
        bool isDictionary = false,
        bool isEnum = false,
        bool isDateLike = false,
        TypeMetadataReference? elementType = null,
        IReadOnlyList<TypeMetadataReference>? typeArguments = null)
    {
        return new TypeMetadataReference(
            Name: name,
            FullName: fullName,
            Namespace: GetNamespace(fullName: fullName),
            IsNullable: isNullable,
            IsCollection: isCollection,
            IsDictionary: isDictionary,
            IsEnum: isEnum,
            IsPrimitive: isPrimitive ?? IsPrimitive(fullName: fullName),
            IsDateLike: isDateLike,
            ElementType: elementType,
            TypeArguments: typeArguments ?? []);
    }

    private static string GetNamespace(string fullName)
    {
        var index = fullName.LastIndexOf(value: '.');
        return index < 0 ? string.Empty : fullName[..index];
    }

    private static bool IsPrimitive(string fullName)
    {
        return fullName is "System.Boolean"
            or "System.Byte"
            or "System.SByte"
            or "System.Int16"
            or "System.UInt16"
            or "System.Int32"
            or "System.UInt32"
            or "System.Int64"
            or "System.UInt64"
            or "System.Single"
            or "System.Double"
            or "System.Decimal"
            or "System.String"
            or "System.Char";
    }
}
